CREATE TABLE `cars` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `id_user` int(11) NOT NULL,
  `id_brand` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `price` decimal(12,2) DEFAULT 0.00,
  `year` int(11) DEFAULT 2024,
  `mileage` int(11) DEFAULT 0,
  `engine_type` varchar(50) DEFAULT '',
  `engine_volume` decimal(3,1) DEFAULT 0.0,
  `horsepower` int(11) DEFAULT 0,
  `transmission` varchar(50) DEFAULT '',
  `drive_type` varchar(50) DEFAULT '',
  `body_type` varchar(50) DEFAULT '',
  `color` varchar(50) DEFAULT '',
  `description` text DEFAULT NULL,
  `img` varchar(255) DEFAULT '',
  `status` tinyint(4) DEFAULT 0,
  `featured` tinyint(4) DEFAULT 0,
  `created_date` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `id_user` (`id_user`),
  KEY `id_brand` (`id_brand`),
  CONSTRAINT `cars_ibfk_1` FOREIGN KEY (`id_user`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `cars_ibfk_2` FOREIGN KEY (`id_brand`) REFERENCES `brands` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=221 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
