INSERT INTO `cars` VALUES (1,53,1,'BMW X5 xDrive40i',6900000.00,2024,0,'Бензин',3.0,340,'Автомат','Полный','Внедорожник','Чёрный','Роскошный полноразмерный SUV с мощным 3-литровым двигателем. Адаптивная подвеска, панорамная крыша, премиальная аудиосистема Harman Kardon.','1771690222_2256cbc7.jpg',1,1,'2026-03-07 06:40:57'),(2,54,1,'BMW 320i M Sport',4200000.00,2024,5000,'Бензин',2.0,184,'Автомат','Задний','Седан','Белый','Спортивный седан с пакетом M Sport. Динамичный дизайн, светодиодные фары, спортивные сиденья и адаптивный круиз-контроль.','1771690222_835cbd96.jpg',1,1,'2026-03-07 06:40:57'),(3,54,1,'BMW X3 xDrive20d',5100000.00,2023,12000,'Дизель',2.0,190,'Автомат','Полный','Кроссовер','Серый','Компактный премиальный кроссовер с экономичным дизелем. Система iDrive 8, беспроводной CarPlay, парковочный ассистент.','1771690222_89b1a064.jpg',1,1,'2026-03-07 06:40:57'),(5,54,2,'Audi Q5 Sportback',5500000.00,2024,0,'Бензин',2.0,265,'Автомат','Полный','Кроссовер','Красный','Стильный кроссовер-купе с полным приводом quattro. Двойной цифровой экран MMI, пневмоподвеска, премиум-интерьер.','1771690222_f0604c63.jpg',1,1,'2026-03-07 06:40:57'),(6,53,2,'Audi A6 55 TFSI',5900000.00,2023,20000,'Бензин',3.0,340,'Автомат','Полный','Седан','Чёрный','Бизнес-класс с мощным V6. Полностью цифровой интерьер, адаптивная пневмоподвеска, система ночного видения.','3r2f14241423.jpg',1,1,'2026-03-07 06:40:57'),(8,54,3,'Mitsubishi Pajero Sport',4100000.00,2023,15000,'Дизель',2.4,181,'Автомат','Полный','Внедорожник','Серебристый','Настоящий внедорожник с рамной конструкцией. Режимы бездорожья, понижающая передача, блокировка дифференциала.','3rwgws32t4t224.jpg',1,0,'2026-03-07 06:40:57'),(9,54,3,'Mitsubishi Eclipse Cross',2600000.00,2024,4000,'Бензин',1.5,150,'Вариатор','Полный','Кроссовер','Оранжевый','Компактный стильный кроссовер. Турбомотор, полный привод, мультимедиа с Apple CarPlay и Android Auto.','3tsg4y6532sdfg.jpg',1,0,'2026-03-07 06:40:57'),(11,54,4,'Chery Tiggo 8 Pro Max',2900000.