INSERT INTO `comments` VALUES (15,1,1,'maria@yandex.ru','<p>Отличная машина! Брал на тест-драйв — впечатления супер. Салон просто&nbsp;</p>','2026-02-19 13:40:58',0,1,5),(16,1,2,'danil@gmail.com','Купил месяц назад, очень доволен. За эти деньги — лучший вариант на рынке. Рекомендую!','2026-02-23 13:40:58',0,1,5),(17,1,3,'maria@yandex.ru','Друг купил такую, катался у него — вау! Теперь сам думаю брать. Комплектация огонь ?','2026-02-11 13:40:58',0,0,5),(18,1,4,'maria@yandex.ru','Была на тест-драйве, покорила с первого взгляда. Дизайн потрясающий, едет уверенно.','2026-02-17 13:40:58',0,0,5),(19,1,5,'danil@gmail.com','Шикарное авто за свои деньги. Много электроники, камера 360, круиз — всё есть из коробки.','2026-02-24 13:40:58',0,0,5),(20,1,6,'danil@gmail.com','Уже 10 000 км проехал — ни одной поломки. Расход в городе вполне адекватный. Советую!','2026-02-28 13:40:58',0,0,5),(21,1,7,'alexey@mail.ru','Пересел с немца на этот авто и не жалею. Комплектация богаче, а цена в 2 раза ниже.','2026-02-18 13:40:58',0,0,5),(25,1,24,'sergei.speed@yandex.ru','Ездили на тест. Динамика хорошая, руль информативный. Подвеска мягкая.','2026-02-19 13:25:31',0,15,3),(26,1,24,'nazarov.andrei@yandex.ru','Отличный вариант для семьи! Багажник большой, посадка удобная для всех.','2026-02-04 10:25:31',0,6,4),(27,1,24,'kovalev.petr@mail.ru','Смотрел лично в салоне. Интерьер впечатляет, всё подогнано ровно.','2026-01-19 12:25:31',0,14,4),(28,1,24,'kovalev.petr@mail.ru','Зарядная инфраструктура в городе уже хорошая. У дома есть зарядка.','2026-01-01 11:25:31',0,32,4),(29,1,25,'ivan.avto@yandex.ru','Проехал 10000 км — никаких нареканий. Расход на трассе 5.2 л/100 км.','2025-11-20 14:25:31',0,22,3),(30,1,25,'nikolai.rider@inbox.ru','Зарядная инфраструктура в городе уже хорошая. У дома есть зарядка.','2026-01-18 04:25:31',0,42,4),(31,1,25,'dmitry.wheel@yandex.ru','5 звёзд от Euro NCAP. AEB работает — уже тормозил на пешехода автоматически.','2026-02-20 03:25:31',0,17,3),(32,1,25,'elena.auto@gmail.c